.prism-wrapper .mp-controls-stack{display:flex;flex-direction:column;gap:4px;margin-top:2px;}
.prism-wrapper .mp-time-row{font-family:Consolas,monospace;font-size:10px;color:rgba(255,255,255,.4);min-width:28px;text-align:right;}
.prism-wrapper input[type=range].mp-slider{-webkit-appearance:none;width:100%;background:transparent;outline:none;cursor:pointer;height:2px;}
.prism-wrapper input[type=range].mp-slider::-webkit-slider-runnable-track{width:100%;height:2px;background:rgba(255,255,255,.1);border-radius:1px;}
.prism-wrapper input[type=range].mp-slider::-webkit-slider-thumb{-webkit-appearance:none;height:8px;width:8px;border-radius:50%;background:#38bdf8;margin-top:-3px;box-shadow:0 0 8px rgba(56,189,248,.8);transition:transform .1s;}
.prism-wrapper input[type=range].mp-slider:hover::-webkit-slider-thumb{transform:scale(1.5);}
.prism-wrapper .play-btn{background:none;border:none;color:#38bdf8;cursor:pointer;opacity:.8;transition:all .2s;display:flex;align-items:center;justify-content:center;}
.prism-wrapper .play-btn:hover{opacity:1;filter:drop-shadow(0 0 4px rgba(56,189,248,.8));transform:scale(1.1);}
.prism-wrapper .play-btn svg{width:14px;height:14px;fill:currentColor;}
.prism-wrapper .vol-icon{width:10px;height:10px;fill:none;stroke:currentColor;stroke-width:2;flex-shrink:0;}
.prism-wrapper .bubble-trigger-zone{position:absolute;inset:60px 20px;z-index:15;cursor:pointer;}
.prism-wrapper .speech-bubble{position:absolute;padding:10px 14px;border-radius:12px;border-bottom-left-radius:2px;background:rgba(127,127,127,.15);backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);border:1px solid rgba(150,150,150,.2);box-shadow:0 4px 15px rgba(0,0,0,.2);color:rgba(255,255,255,.9);font-size:12px;line-height:1.5;pointer-events:none;z-index:100;max-width:200px;animation:bubblePop .4s cubic-bezier(.34,1.56,.64,1) forwards;transform-origin:bottom left;}
.prism-wrapper .speech-bubble.fading{animation:bubbleDissolve 1s ease-out forwards;}
@keyframes slideUpFade{from{opacity:0;transform:translateY(10px);}to{opacity:1;transform:translateY(0);}}
@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 10px rgba(56,189,248,.8);}50%{opacity:.4;box-shadow:0 0 4px rgba(56,189,248,.3);}}
@keyframes spin{from{transform:rotate(0deg);}to{transform:rotate(360deg);}}
@keyframes bubblePop{from{opacity:0;transform:scale(.8) translateY(5px);}to{opacity:1;transform:scale(1) translateY(0);}}
@keyframes bubbleDissolve{0%{opacity:1;filter:blur(0px);}100%{opacity:0;filter:blur(4px);transform:translateY(-10px);}}
.prism-wrapper.lt{background:transparent!important;}
.prism-wrapper.lt .p-island{color:rgba(0,0,0,.8)!important;border-color:rgba(0,0,0,.08)!important;background:rgba(0,0,0,.03)!important;box-shadow:0 4px 16px rgba(0,0,0,.05)!important;backdrop-filter:blur(24px)!important;}
.prism-wrapper.lt .p-island.collapsed:hover{border-color:rgba(56,189,248,.35)!important;box-shadow:0 0 24px rgba(56,189,248,.1),0 6px 20px rgba(0,0,0,.08)!important;}
.prism-wrapper.lt .p-island.expanded:hover{border-color:rgba(56,189,248,.25)!important;}
.prism-wrapper.lt .gb{background:radial-gradient(400px circle at var(--mouse-x) var(--mouse-y),rgba(0,0,0,.06),transparent 40%)!important;}
.prism-wrapper.lt .gi{background:radial-gradient(300px circle at var(--mouse-x) var(--mouse-y),rgba(56,189,248,.12),transparent 40%)!important;}
.prism-wrapper.lt .lb{color:rgba(56,189,248,.9)!important;}
.prism-wrapper.lt .capsule-content{color:rgba(0,0,0,.85)!important;}
.prism-wrapper.lt .meta{border-bottom-color:rgba(0,0,0,.08)!important;}
.prism-wrapper.lt .main-title{color:rgba(0,0,0,.85)!important;}
.prism-wrapper.lt .tg-close{border-color:rgba(56,189,248,.4)!important;color:rgba(56,189,248,.8)!important;}
.prism-wrapper.lt .tg-close:hover{color:rgba(56,189,248,1)!important;background:rgba(56,189,248,.08)!important;}
.prism-wrapper.lt .detail-glass-box{background:rgba(0,0,0,.02)!important;color:rgba(0,0,0,.8)!important;border-left-color:rgba(56,189,248,.6)!important;}
.prism-wrapper.lt .dh-title{color:rgba(56,189,248,.9)!important;border-bottom-color:rgba(0,0,0,.08)!important;}
.prism-wrapper.lt .text-desc{color:rgba(0,0,0,.7)!important;}
.prism-wrapper.lt .dr{border-top-color:rgba(0,0,0,.08)!important;}
.prism-wrapper.lt .dh-btn{border-color:rgba(0,0,0,.08)!important;background:rgba(0,0,0,.02)!important;color:rgba(0,0,0,.5)!important;}
.prism-wrapper.lt .dh-btn:hover{border-color:rgba(56,189,248,.3)!important;color:rgba(56,189,248,.9)!important;}
.prism-wrapper.lt .dh-btn.on{border-color:rgba(56,189,248,.5)!important;background:rgba(56,189,248,.08)!important;color:rgba(56,189,248,1)!important;}
.prism-wrapper.lt .setting-input{background:rgba(0,0,0,.02)!important;border-color:rgba(0,0,0,.1)!important;color:rgba(0,0,0,.8)!important;}
.prism-wrapper.lt .setting-input:focus{border-color:rgba(56,189,248,.5)!important;}
.prism-wrapper.lt .mp-title{color:rgba(0,0,0,.85)!important;}
.prism-wrapper.lt .mp-artist{color:rgba(56,189,248,.85)!important;}
.prism-wrapper.lt .mp-time-row{color:rgba(0,0,0,.5)!important;}
.prism-wrapper.lt .mp-vinyl-disc{background:radial-gradient(circle at center,#e0e0e0,#ccc)!important;border-color:rgba(0,0,0,.15)!important;}
.prism-wrapper.lt input[type=range].mp-slider::-webkit-slider-runnable-track{background:rgba(0,0,0,.1)!important;}
