    // ── 核心驱动模型管理 (四大模式精准互斥与分配) ──
    const ALL_MODEL_PROMPTS = [
      "✨ Gemini",
      "✨Gemini✨",
      "🎨 Claude",
      "🎨Claude🎨",
      "—\\✨思考模式（简）",
