    pdoc.getElementById(`${ID}-cot-claude`)?.addEventListener("click", () => setModel("claude"));
    pdoc.getElementById(`${ID}-cot-c45s`)?.addEventListener("click", () => setModel("c45s"));
    pdoc.getElementById(`${ID}-cot-deepseek`)?.addEventListener("click", () => setModel("deepseek"));

    pdoc.getElementById(`${ID}-rec-toggle`)?.addEventListener("click", (e) => {
      if (pwin.orbEditMode) return;
      const rec = MODEL_REC_CONFIG[savedModel];
      if (!rec || (rec.on.length === 0 && rec.off.length === 0)) return;

      recEnabled = !recEnabled;
      const btn = e.currentTarget;
      btn.classList.toggle("is-on", recEnabled);

      if (recEnabled) {
         rec.on.forEach(kw => ensureOn(kw));
         rec.off.forEach(kw => ensureOff(kw));
      } else {
         // Optionally do nothing on turn off, or revert. Revert is hard without state tracking. 
         // Assuming turning off just turns off the "on" items
         rec.on.forEach(kw => ensureOff(kw));
